// Descargar el audio del video para enviarlo a Groq Whisper
// Groq acepta URLs públicas directas o base64.
// Este nodo prepara la URL del video y la pasa al siguiente paso.
// Si la URL no es descargable directamente (IG/TT requieren auth),
// usamos el caption como fallback y lo marcamos.

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Determinar si tenemos URL descargable real
  const hasDirectVideo = d.video_url &&
    d.video_url !== d.url &&
    (d.video_url.includes('.mp4') || d.video_url.includes('download') || d.video_url.includes('video'));

  results.push({ json: {
    ...d,
    has_direct_video: hasDirectVideo,
    transcripcion_fallback: d.caption  // Si no hay video descargable, usamos caption
  }});
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const raw = item.json.content?.[0]?.text || '{}';
    const clean = raw
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();
    const ai = JSON.parse(clean);
    const ref = $('Preservar datos referente').item.json;

    const CATS = ['<<CATEGORIA_1>>', '<<CATEGORIA_2>>', '<<CATEGORIA_3>>', '<<CATEGORIA_4>>', '<<CATEGORIA_5>>'];
    const categoria = CATS.includes(ai.categoria) ? ai.categoria : '<<CATEGORIA_1>>';

    results.push({ json: {
      "TITULO (contexto)":                    ai.titulo_contexto || '',
      "🎯 ENLACE DE REFERENTE":               ref.url || '',
      "FORMATO":                              ai.formato || '',
      "DIFICULTAD":                           ai.dificultad || '',
      "CATEGORIAS":                           categoria,
      "SCRIPT":                               ai.script || '',
      "DURACION":                             ai.duracion_estimada || '',
      "FECHA DE PUBLICACION DE REFERENTE":    ref.fecha_ref || '',
      "🗂️ STATUS":                            'HACER GUION',
      "FECHA ULTIMA REVISIÓN":                $now.toISO().split('T')[0],
      "EDITOR":                               '<<NOMBRE_DEL_EDITOR>>',
      "COMENTARIOS":                          `Hook: ${ai.hook || ''}`,
      "PLATAFORMA":                           ref.plataforma || '',
      "AUTOR":                                ref.autor || '',
      "SEGUIDORES":                           Number(ref.seguidores || 0),
      "LIKES":                                Number(ref.likes || 0),
      "VISTAS":                               Number(ref.vistas || 0),
      "ENGAGEMENT":                           Number(ref.engagement || 0),
      "SCORE":                                Number(ref.score || 0),
      "HASHTAGS":                             ref.hashtags || ''
    }});
  } catch(e) {
    console.error('Error:', e.message, '| Raw:', item.json.content?.[0]?.text?.substring(0, 200));
  }
}

return results;

const total = $input.all().length;
const p = $('Parámetros de corrida').first().json;
console.log(`✅ Flujo de <<NOMBRE_AGENCIA>> completado. ${total} referentes procesados y escritos en BENCHMARKGRABAR.`);
return [{ json: {
  total: total,
  fecha: new Date().toLocaleDateString('es-CO', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
  origen: p.origen === 'formulario' ? 'búsqueda desde el formulario' : 'corrida programada (cron)',
  filtros: p.resumen_filtros,
  sheet: 'https://docs.google.com/spreadsheets/d/<<GOOGLE_SHEET_ID>>'
}}];

const item = $input.item.json;
const seguidores = item.ownerFollowersCount || item.ownerFollowerCount || 0;

const hoy = $now.toISO().split('T')[0];

const fechaPublicacion = (() => {
  if (!item.timestamp) return '';
  const ts = Number(item.timestamp);
  if (isNaN(ts) || ts <= 0) return '';
  const d = new Date(ts * 1000);
  if (isNaN(d.getTime())) return '';
  return d.toISOString().split('T')[0];
})();

return {
  json: {
    plataforma: 'instagram',
    username: item.ownerUsername || '',
    nombre: item.ownerFullName || '',
    seguidores: seguidores,
    bio: item.ownerBio || '',
    descripcion: item.caption || '',
    likes: item.likesCount || 0,
    comentarios: item.commentsCount || 0,
    reproducciones: item.videoViewCount || 0,
    url: item.url || '',
    perfil_url: 'https://instagram.com/' + (item.ownerUsername || ''),
    hashtags: (item.hashtags || []).join(', '),
    duracion_video: item.videoDuration || 0,
    is_video: item.isVideo || false,
    tipo_post: item.type || 'Image',
    engagement_rate: seguidores > 0
      ? (((item.likesCount || 0) + (item.commentsCount || 0)) / seguidores * 100).toFixed(2) + '%'
      : '0%',
    fecha_publicacion: fechaPublicacion,
    fecha: hoy
  }
};

// Combinar transcripción con datos del referente
// Prioridad: 1) Supadata response.text, 2) fallback transcripcion field, 3) caption
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  let transcripcion = '';

  // 1. Check if Supadata returned a successful response with text field
  if (data?.text && typeof data.text === 'string' && data.text.length > 20) {
    transcripcion = data.text;
    console.log('Using Supadata transcription for:', data.url || data.video_url);
  }
  // 2. Check if fallback node set transcripcion field
  else if (data?.transcripcion && typeof data.transcripcion === 'string' && data.transcripcion.length > 0) {
    transcripcion = data.transcripcion;
    console.log('Using fallback transcripcion for:', data.url || data.video_url);
  }
  // 3. Final fallback to caption
  else if (data?.caption) {
    transcripcion = data.caption;
    console.log('Using caption as final fallback for:', data.url || data.video_url);
  }
  else {
    transcripcion = 'Sin transcripción disponible';
    console.log('No transcription available for:', data.url || data.video_url);
  }

  results.push({ json: {
    ...data,
    transcripcion: transcripcion.substring(0, 4000)
  }});
}

return results;

