// Lee los parámetros de la corrida (cron = defaults del cliente; formulario = lo elegido ahí).
const p = $('Parámetros de corrida').first().json;

const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const TEMAS = (p.temas || []).map(norm).filter(Boolean);
const HASHTAGS = (p.hashtags || []).map(h => norm(h).replace(/^#/, '')).filter(Boolean);
const TIPOS = p.tipos_contenido || [];
const PLATAFORMAS = (p.plataformas && p.plataformas.length) ? p.plataformas.map(norm) : ['instagram', 'tiktok'];
const ahora = Date.now();
const maxEdadMs = (Number(p.dias_recencia) || 0) * 86400000;

const filtered = $input.all()
  .map(item => {
    const d = item.json;
    if (!d.url) return null;

    const likes  = Number(d.likes || 0);
    const vistas = Number(d.reproducciones || 0);
    const segs   = Number(d.seguidores || 0);

    if (!PLATAFORMAS.includes(norm(d.plataforma))) return null;

    // viral: pasa si supera AL MENOS UNO de los umbrales
    if (!(likes >= p.min_likes || vistas >= p.min_views || segs >= p.min_seguidores)) return null;

    // temas (lista vacía = sin filtro de tema)
    const txt = norm(' ' + (d.descripcion || '') + ' ' + (d.hashtags || '') + ' ');
    if (TEMAS.length && !TEMAS.some(t => txt.includes(t))) return null;

    // hashtags específicos (intersección con los del item)
    if (HASHTAGS.length) {
      const propios = norm(d.hashtags || '').split(',').map(h => h.trim().replace(/^#/, '')).filter(Boolean);
      if (!HASHTAGS.some(h => propios.includes(h))) return null;
    }

    // tipo de contenido: short (video ≤ 90 s) | video | imagen
    if (TIPOS.length) {
      const dur = Number(d.duracion_video || 0);
      const esVideo = !!d.is_video || d.tipo_post === 'Video';
      const ok = TIPOS.some(t =>
        (t === 'short'  && esVideo && dur > 0 && dur <= 90) ||
        (t === 'video'  && esVideo) ||
        (t === 'imagen' && !esVideo));
      if (!ok) return null;
    }

    // recencia
    if (maxEdadMs > 0) {
      const f = Date.parse(d.fecha_publicacion || '');
      if (!Number.isFinite(f) || (ahora - f) > maxEdadMs) return null;
    }

    return { json: {
      plataforma: d.plataforma || '',
      url: d.url,
      video_url: d.url,
      autor: d.username || '',
      nombre: d.nombre || '',
      seguidores: segs,
      likes,
      vistas,
      engagement: parseFloat(d.engagement_rate) || 0,
      duracion_seg: Number(d.duracion_video || 0),
      caption: (d.descripcion || '').substring(0, 800),
      hashtags: d.hashtags || '',
      fecha_ref: d.fecha_publicacion || '',
      score: likes + Math.floor(vistas / 10) + Math.floor(segs / 1000)
    }};
  })
  .filter(Boolean)
  .sort((a, b) => b.json.score - a.json.score)
  .slice(0, Number(p.top_n) || 25);

return filtered;

// Convergencia de triggers (cron + formulario): arma los parámetros de ESTA corrida.
// Defaults del cliente vía placeholders <<...>>; si la corrida vino del formulario,
// lo elegido ahí los sobreescribe SOLO para esta corrida.
const j = $input.first().json;

const num = (v, fb) => {
  if (v === '' || v === null || v === undefined) return fb;
  if (String(v).includes('<<')) return fb;
  const n = Number(v);
  return Number.isFinite(n) ? n : fb;
};
const lista = (v) => String(v || '').split(',').map(s => s.trim()).filter(s => s && !s.includes('<<'));

const DEFAULTS = {
  plataformas:      ['instagram', 'tiktok'],
  min_likes:        num('<<MIN_LIKES>>', 10000),
  min_views:        num('<<MIN_VIEWS>>', 100000),
  min_seguidores:   num('<<MIN_SEGUIDORES>>', 500000),
  temas:            lista('<<TEMA_1>>,<<TEMA_2>>,<<TEMA_3>>,<<TEMA_4>>,<<TEMA_5>>'),
  hashtags:         [],            // [] = sin filtro de hashtags
  tipos_contenido:  [],            // [] = cualquier tipo
  dias_recencia:    num('<<DIAS_RECENCIA>>', 0),   // 0 = sin límite de fecha
  top_n:            num('<<TOP_N>>', 25),
  ig_results_limit: num('<<IG_RESULTS_LIMIT>>', 12),
  tt_results_limit: num('<<TT_RESULTS_LIMIT>>', 60)
};

const esForm = j.submittedAt !== undefined;
const p = { ...DEFAULTS, origen: esForm ? 'formulario' : 'cron' };

if (esForm) {
  const PLAT = { 'Ambas': ['instagram', 'tiktok'], 'Solo Instagram': ['instagram'], 'Solo TikTok': ['tiktok'] };
  const TIPO = { 'Cualquiera': [], 'Short-form (video ≤ 90 s)': ['short'], 'Video': ['video'], 'Imagen / carrusel': ['imagen'] };
  if (PLAT[j['Plataformas']]) p.plataformas = PLAT[j['Plataformas']];
  p.min_likes      = num(j['Mínimo de likes'], p.min_likes);
  p.min_views      = num(j['Mínimo de views'], p.min_views);
  p.min_seguidores = num(j['Mínimo de seguidores'], p.min_seguidores);
  const temasForm = lista(j['Temas (separados por coma)']);
  if (temasForm.includes('*')) p.temas = [];        // '*' = buscar sin filtro de tema
  else if (temasForm.length) p.temas = temasForm;
  p.hashtags = lista(j['Hashtags (separados por coma)']).map(h => h.replace(/^#/, '').toLowerCase());
  if (TIPO[j['Tipo de contenido']]) p.tipos_contenido = TIPO[j['Tipo de contenido']];
  p.dias_recencia = num(j['Recencia (días)'], p.dias_recencia);
  p.top_n         = num(j['Cuántos referentes (top N)'], p.top_n);
}

p.resumen_filtros = [
  'Plataformas: ' + p.plataformas.join(', '),
  'Mínimos — likes: ' + p.min_likes + ' · views: ' + p.min_views + ' · seguidores: ' + p.min_seguidores,
  'Temas: ' + (p.temas.length ? p.temas.join(', ') : 'sin filtro'),
  'Hashtags: ' + (p.hashtags.length ? p.hashtags.join(', ') : 'sin filtro'),
  'Tipo de contenido: ' + (p.tipos_contenido.length ? p.tipos_contenido.join(', ') : 'cualquiera'),
  'Recencia: ' + (p.dias_recencia > 0 ? 'últimos ' + p.dias_recencia + ' días' : 'sin límite'),
  'Top N: ' + p.top_n
].join('\n');

return [{ json: p }];

// Arma el batch de outputs para el registro central (contrato: core/contracts/ingesta-registro.md).
// Si "Abrir run" falló (Supabase caído), run_id queda null: el POST fallará y el flujo sigue —
// el registro es sumidero, nunca dependencia.
const run = $('Abrir run en el registro').first().json || {};
const run_id = run.id || null;

const outputs = $input.all().map(f => {
  const d = f.json;
  return {
    run_id: run_id,
    tipo: 'guion_reel',
    titulo: d['TITULO (contexto)'] || '(sin título)',
    contenido_o_link: d['SCRIPT'] || '',
    estado: 'draft',
    source_items: [{ platform: d['PLATAFORMA'] || '', url: d['🎯 ENLACE DE REFERENTE'] || '' }],
    metadata: {
      views: Number(d['VISTAS'] || 0),
      likes: Number(d['LIKES'] || 0),
      followers: Number(d['SEGUIDORES'] || 0),
      engagement: Number(d['ENGAGEMENT'] || 0),
      score: Number(d['SCORE'] || 0),
      hashtags: String(d['HASHTAGS'] || '').split(',').map(s => s.trim()).filter(Boolean),
      categoria: d['CATEGORIAS'] || '',
      plataforma: d['PLATAFORMA'] || ''
    }
  };
});

return [{ json: { run_id: run_id, n: outputs.length, outputs: outputs } }];
